SELECT COUNT(*)
FROM xeus.crms_rqst_renew AS tt LEFT JOIN xeus.mt_cmm_cde AS renew_typ_rel ON renew_typ_rel.grp_cde = 'C56' AND renew_typ_rel.cde_cde = tt.renew_typ LEFT JOIN ( SELECT crms_user.user_id, orgz.org_nm AS office_nm, crms_user.user_nm, crms_user.depart_nm AS dept_nm, crms_user.pos_nm, crms_user.tel_num, crms_user.auth_stat_cd AS user_stat_cd FROM xeus.mt_usr_desc crms_user LEFT JOIN xeus.mt_orgz_desc orgz ON orgz.org_mgr_no = crms_user.org_mgr_no ) AS acpt_user_id_rel ON acpt_user_id_rel.user_id = tt.acpt_user_id LEFT JOIN xeus.crms_trans_rqst AS rqst ON rqst.mgr_seq = tt.rqst_mgr_seq LEFT JOIN ( SELECT crms_user.user_id, orgz.org_nm AS office_nm, crms_user.user_nm, crms_user.depart_nm AS dept_nm, crms_user.pos_nm, crms_user.tel_num, crms_user.auth_stat_cd AS user_stat_cd FROM xeus.mt_usr_desc crms_user LEFT JOIN xeus.mt_orgz_desc orgz ON orgz.org_mgr_no = crms_user.org_mgr_no ) AS rqst_reqst_id_rel ON rqst_reqst_id_rel.user_id = rqst.reqst_id LEFT JOIN xeus.mt_cmm_cde AS rqst_crime_typ_rel ON rqst_crime_typ_rel.grp_cde = 'C51' AND rqst_crime_typ_rel.cde_cde = rqst.crime_typ LEFT JOIN xeus.crms_trans_avi AS avi ON avi.mgr_seq = tt.avi_mgr_seq AND avi.rqst_mgr_seq = tt.rqst_mgr_seq LEFT JOIN xeus.crms_trans_work AS work ON work.file_seq = tt.file_seq AND work.avi_mgr_seq = tt.avi_mgr_seq AND work.rqst_mgr_seq = tt.rqst_mgr_seq LEFT JOIN xeus.asset_cctv AS cctv_no_rel ON cctv_no_rel.mgr_no = avi.cctv_mgr_no
AND tt.mgr_seq = #{mgrSeq}::numeric
AND tt.rqst_mgr_seq = #{rqstMgrSeq}::numeric
AND tt.avi_mgr_seq = #{aviMgrSeq}::numeric
AND tt.file_seq = #{fileSeq}::numeric
AND tt.renew_typ = #{renewTyp}
AND rqst.reqst_id LIKE '%'||#{reqstId}||'%'
AND rqst_reqst_id_rel.user_nm LIKE '%'||#{userNm}||'%'
AND rqst.crime_typ = #{crimeTyp}
AND tt.reqst_dat >= #{startDat}
AND tt.reqst_dat <= #{endDat}
AND tt.acpt_yn is null

SELECT tt.mgr_seq, tt.avi_mgr_seq, tt.rqst_mgr_seq, tt.file_seq, tt.renew_typ, tt.reqst_dat, tt.reqst_resn, tt.acpt_dat, tt.acpt_user_id, tt.acpt_yn, tt.rejt_resn , tt.play_limit_cnt, tt.play_limit_dat , renew_typ_rel.cde_nm AS renew_typ_rel_cde_nm, acpt_user_id_rel.user_nm AS acpt_user_id_rel_user_nm , rqst.reqst_id AS rqst_reqst_id, rqst_reqst_id_rel.user_nm AS rqst_reqst_id_rel_cde_nm, rqst.crime_typ AS rqst_crime_typ, rqst_crime_typ_rel.cde_nm AS rqst_crime_typ_rel_cde_nm , avi.cctv_mgr_no AS avi_cctv_mgr_no, avi.play_limit_cnt AS avi_play_limit_cnt, avi.play_limit_dat AS avi_play_limit_dat , work.file_nm AS work_file_nm , cctv_no_rel.cctv_nm AS cctv_no_rel_label
, rqst.req_gbn_cd
FROM xeus.crms_rqst_renew AS tt LEFT JOIN xeus.mt_cmm_cde AS renew_typ_rel ON renew_typ_rel.grp_cde = 'C56' AND renew_typ_rel.cde_cde = tt.renew_typ LEFT JOIN ( SELECT crms_user.user_id, orgz.org_nm AS office_nm, crms_user.user_nm, crms_user.depart_nm AS dept_nm, crms_user.pos_nm, crms_user.tel_num, crms_user.auth_stat_cd AS user_stat_cd FROM xeus.mt_usr_desc crms_user LEFT JOIN xeus.mt_orgz_desc orgz ON orgz.org_mgr_no = crms_user.org_mgr_no ) AS acpt_user_id_rel ON acpt_user_id_rel.user_id = tt.acpt_user_id LEFT JOIN xeus.crms_trans_rqst AS rqst ON rqst.mgr_seq = tt.rqst_mgr_seq LEFT JOIN ( SELECT crms_user.user_id, orgz.org_nm AS office_nm, crms_user.user_nm, crms_user.depart_nm AS dept_nm, crms_user.pos_nm, crms_user.tel_num, crms_user.auth_stat_cd AS user_stat_cd FROM xeus.mt_usr_desc crms_user LEFT JOIN xeus.mt_orgz_desc orgz ON orgz.org_mgr_no = crms_user.org_mgr_no ) AS rqst_reqst_id_rel ON rqst_reqst_id_rel.user_id = rqst.reqst_id LEFT JOIN xeus.mt_cmm_cde AS rqst_crime_typ_rel ON rqst_crime_typ_rel.grp_cde = 'C51' AND rqst_crime_typ_rel.cde_cde = rqst.crime_typ LEFT JOIN xeus.crms_trans_avi AS avi ON avi.mgr_seq = tt.avi_mgr_seq AND avi.rqst_mgr_seq = tt.rqst_mgr_seq LEFT JOIN xeus.crms_trans_work AS work ON work.file_seq = tt.file_seq AND work.avi_mgr_seq = tt.avi_mgr_seq AND work.rqst_mgr_seq = tt.rqst_mgr_seq LEFT JOIN xeus.asset_cctv AS cctv_no_rel ON cctv_no_rel.mgr_no = avi.cctv_mgr_no
AND tt.mgr_seq = #{mgrSeq}::numeric
AND tt.rqst_mgr_seq = #{rqstMgrSeq}::numeric
AND tt.avi_mgr_seq = #{aviMgrSeq}::numeric
AND tt.file_seq = #{fileSeq}::numeric
AND tt.renew_typ = #{renewTyp}
AND rqst.reqst_id LIKE '%'||#{reqstId}||'%'
AND rqst_reqst_id_rel.user_nm LIKE '%'||#{userNm}||'%'
AND rqst.crime_typ = #{crimeTyp}
AND tt.reqst_dat >= #{startDat}
AND tt.reqst_dat <= #{endDat}
AND tt.acpt_yn is null
${sortCol} ${sortTyp}
tt.mgr_seq DESC
LIMIT ${limit} OFFSET ${offset}

SELECT mgr_seq, avi_mgr_seq, rqst_mgr_seq, file_seq, renew_typ, reqst_dat, reqst_resn, acpt_dat, acpt_user_id, acpt_yn, rejt_resn, play_limit_cnt, play_limit_dat
FROM xeus.crms_rqst_renew




        AND mgr_seq = #{mgrSeq}

mapper.update:
UPDATE xeus.crms_rqst_renew
SET

    acpt_dat = #{acptDat}
    , acpt_user_id = #{acptUserId}
    , acpt_yn = #{acptYn}

    , play_limit_cnt = #{playLimitCnt}::numeric
    , play_limit_dat = #{playLimitDat}
WHERE mgr_seq = #{mgrSeq}::numeric;

UPDATE xeus.crms_trans_rqst
SET
    proc_stat_cd = 'SN'
WHERE mgr_seq = #{rqstMgrSeq}::numeric;

UPDATE xeus.crms_trans_work
SET
    reenc_yn = 'Y',
    down_cnt = 0
WHERE avi_mgr_seq = #{aviMgrSeq}::numeric
    AND rqst_mgr_seq = #{rqstMgrSeq}::numeric
    AND file_seq = #{fileSeq}::numeric;

UPDATE xeus.crms_rqst_renew
SET
    acpt_dat = #{acptDat}
    , acpt_user_id = #{acptUserId}
    , acpt_yn = #{acptYn}
    , rejt_resn = #{rejtResn}
WHERE mgr_seq = #{mgrSeq}::numeric;

mapper.select:
SELECT (CASE WHEN char_length(tt.acpt_yn) > 0 THEN tt.acpt_yn ELSE 'NON' END) AS acpt_yn, COUNT(*) AS cnt
FROM xeus.crms_rqst_renew AS tt
    LEFT JOIN xeus.crms_trans_rqst AS rqst ON rqst.mgr_seq = tt.rqst_mgr_seq



        AND renew_typ = #{renewTyp}



        AND user_id = #{userId}


GROUP BY tt.acpt_yn
